	"syscall"
	"testing"
	"time"
)

// P0 overlay addressing: the inner /24 carried by the WireGuard TUN on both ends.
const (
	edgeInner  = "10.10.0.1"
	concInner  = "10.10.0.2"
	tunDev     = "wanbond0"
	listenPort = 51820
)

// TestP0PassThrough is the P0 acceptance gate: bring the wanbond tunnel up over a
// single path (no bonding) with the pass-through Bind, complete the WireGuard
// handshake, and verify both ICMP (ping) and a TCP bulk transfer (iperf3) flow
// through the tunnel between the edge and concentrator network namespaces.
func TestP0PassThrough(t *testing.T) {
	top := Setup(t)
	p := top.path("starlink")
	bin := buildWanbond(t)

	edgePriv, edgePub := genKey(t)
	concPriv, concPub := genKey(t)
	psk := randKey(t) // outer-control PSK: required by config validation, unused by P0 pass-through

	dir := t.TempDir()
	edgeCfg := writeConfig(t, filepath.Join(dir, "edge.toml"), fmt.Sprintf(`role = "edge"
psk = "%s"

[[paths]]
name = "starlink"
source_addr = "%s"

[wireguard]
private_key = "%s"

[[wireguard.peers]]
public_key = "%s"
endpoint = "%s:%d"
allowed_ips = ["%s/32"]

[log]
level = "error"
`, psk, p.edgeIP, edgePriv, concPub, p.concIP, listenPort, concInner))

	concCfg := writeConfig(t, filepath.Join(dir, "conc.toml"), fmt.Sprintf(`role = "concentrator"
psk = "%s"

[[paths]]
name = "starlink"
source_addr = "%s"

[wireguard]
private_key = "%s"
listen_port = %d

[[wireguard.peers]]
public_key = "%s"
allowed_ips = ["%s/32"]

[log]
level = "error"
`, psk, p.concIP, concPriv, listenPort, edgePub, edgeInner))

	// Concentrator first (it must be listening before the edge initiates), then edge.
	conc := top.startProc(t, "concentrator", "nsenter", "-t", strconv.Itoa(top.pid), "-n", bin, "--config", concCfg)
	edge := top.startProc(t, "edge", bin, "--config", edgeCfg)

	// Wait for each side's TUN, then address it (wanbond owns the engine only;
	// addressing is the operator's job — here, the test's).
	if !top.waitLink(tunDev, false, 5*time.Second) {
		t.Fatalf("edge %s never appeared\n%s", tunDev, edge.log())
	}
	if !top.waitLink(tunDev, true, 5*time.Second) {
		t.Fatalf("concentrator %s never appeared\n%s", tunDev, conc.log())
	}
	top.run("ip", "addr", "add", edgeInner+"/24", "dev", tunDev)
	top.run("ip", "link", "set", tunDev, "up")
	top.nsenter("ip", "addr", "add", concInner+"/24", "dev", tunDev)
	top.nsenter("ip", "link", "set", tunDev, "up")

	// The first ping triggers the handshake; retry until the session is established.
	if !top.pingUntil(concInner, 15*time.Second) {
		t.Fatalf("tunnel never came up: %s unreachable through the tunnel\n--- edge ---\n%s\n--- concentrator ---\n%s",
			concInner, edge.log(), conc.log())
	}

	mbps := top.iperf3Mbps(t, concInner, 3)
	if mbps <= 0 {
		t.Fatalf("iperf3 through the tunnel measured non-positive throughput %.2f Mbit/s", mbps)
	}
	t.Logf("P0 tunnel up: handshake + ping OK, iperf3 = %.1f Mbit/s", mbps)
}

// buildWanbond compiles the daemon (plain build, no e2e tag) into a temp path and
// returns it. The build uses the module-qualified package path so it resolves
// regardless of the test's working directory.
func buildWanbond(t *testing.T) string {
	t.Helper()
	bin := filepath.Join(t.TempDir(), "wanbond")
	out, err := exec.Command("go", "build", "-o", bin, "github.com/7mind/wanbond/cmd/wanbond").CombinedOutput()
	if err != nil {
		t.Fatalf("build wanbond: %v\n%s", err, out)
	}
	return bin
}

// genKey generates an X25519 keypair (the WireGuard key format) using the
// standard library, returning both keys base64-encoded as the TOML config
// carries them.
func genKey(t *testing.T) (privB64, pubB64 string) {
	t.Helper()
	priv, err := ecdh.X25519().GenerateKey(rand.Reader)
	if err != nil {
		t.Fatalf("generate X25519 key: %v", err)
	}
	return base64.StdEncoding.EncodeToString(priv.Bytes()),
		base64.StdEncoding.EncodeToString(priv.PublicKey().Bytes())
}

// randKey returns 32 random bytes base64-encoded (a placeholder PSK).
func randKey(t *testing.T) string {
	t.Helper()
	var b [32]byte
	if _, err := rand.Read(b[:]); err != nil {
		t.Fatalf("read random: %v", err)
	}
	return base64.StdEncoding.EncodeToString(b[:])
}

// writeConfig writes body to path with the exact 0600 mode config.Load requires.
func writeConfig(t *testing.T, path, body string) string {
	t.Helper()
	if err := os.WriteFile(path, []byte(body), 0o600); err != nil {
		t.Fatalf("write config %s: %v", path, err)
	}
	if err := os.Chmod(path, 0o600); err != nil { // defeat umask widening
		t.Fatalf("chmod config %s: %v", path, err)
	}
	return path
}

// lockedBuffer is a bytes.Buffer safe for concurrent Write (by exec.Cmd's output
// copier goroutine) and String (by the test's diagnostic log() calls).
type lockedBuffer struct {
	mu  sync.Mutex
	buf bytes.Buffer
}

func (b *lockedBuffer) Write(p []byte) (int, error) {
	b.mu.Lock()
	defer b.mu.Unlock()
	return b.buf.Write(p)
}

func (b *lockedBuffer) String() string {
	b.mu.Lock()
	defer b.mu.Unlock()
	return b.buf.String()
}

// proc is a background process with captured combined output.
type proc struct {
	cmd    *exec.Cmd
	name   string
	output *lockedBuffer
}

func (p *proc) log() string { return p.output.String() }

// startProc launches argv in the background, capturing its combined output and
// registering a cleanup that terminates it (SIGTERM, then SIGKILL after a grace
// period). A concentrator process is launched via nsenter so it runs — and
// creates its TUN — inside the peer network namespace.
func (top *Topology) startProc(t *testing.T, name string, argv ...string) *proc {
	t.Helper()
	cmd := exec.Command(argv[0], argv[1:]...)
	out := &lockedBuffer{}
	cmd.Stdout, cmd.Stderr = out, out
	if err := cmd.Start(); err != nil {
		t.Fatalf("start %s (%v): %v", name, argv, err)
	}
	p := &proc{cmd: cmd, name: name, output: out}
	t.Cleanup(func() {
		if cmd.Process == nil {
			return
		}
		_ = cmd.Process.Signal(syscall.SIGTERM)
		done := make(chan struct{})
		// cmd.Wait (not Process.Wait) reaps the child AND waits for the output
		// copier goroutines, so no write races the final log() read.
		go func() { _ = cmd.Wait(); close(done) }()
		select {
		case <-done:
		case <-time.After(2 * time.Second):
			_ = cmd.Process.Kill()
			<-done
		}
	})
	return p
}

// waitLink polls until dev exists (in the peer netns when ns is true), up to d.
func (top *Topology) waitLink(dev string, ns bool, d time.Duration) bool {
	deadline := time.Now().Add(d)
	for time.Now().Before(deadline) {
		var err error
		if ns {
			err = top.tryRun("nsenter", "-t", strconv.Itoa(top.pid), "-n", "ip", "link", "show", dev)
		} else {
			err = top.tryRun("ip", "link", "show", dev)
		}
		if err == nil {
			return true
		}
		time.Sleep(100 * time.Millisecond)
	}
	return false
}

// pingUntil pings ip from the edge netns until it answers or d elapses. The first
// successful reply implies the WireGuard session is established.
func (top *Topology) pingUntil(ip string, d time.Duration) bool {
	deadline := time.Now().Add(d)
	for time.Now().Before(deadline) {
		if top.tryRun("ping", "-c", "1", "-W", "1", ip) == nil {
			return true
		}
		time.Sleep(200 * time.Millisecond)
	}
	return false
}

// iperfDefaultPort is iperf3's default server port (5201), used by iperf3Mbps,
// which starts its server without an explicit -p. The under-load measurement uses
// the distinct bloatPort instead.
const iperfDefaultPort = 5201

// iperf3Mbps runs a one-shot iperf3 TCP transfer to serverIP (inside the peer
// netns) for secs seconds and returns the sender throughput in Mbit/s.
func (top *Topology) iperf3Mbps(t *testing.T, serverIP string, secs int) float64 {
	t.Helper()
	top.startProc(t, "iperf3-server", "nsenter", "-t", strconv.Itoa(top.pid), "-n", "iperf3", "-s", "-1", "-B", serverIP)
	top.waitIperfListen(t, iperfDefaultPort) // poll for LISTEN (never connect: server is one-shot)

	out := top.runOut("iperf3", "-c", serverIP, "-t", strconv.Itoa(secs), "-J")
	var r struct {
		End struct {
			SumSent struct {
				BitsPerSecond float64 `json:"bits_per_second"`
			} `json:"sum_sent"`
		} `json:"end"`
	}
	if err := json.Unmarshal([]byte(out), &r); err != nil {
		t.Fatalf("parse iperf3 json: %v\n%s", err, out)
	}
	return r.End.SumSent.BitsPerSecond / 1e6
}

//go:build e2e

package e2e

import (
	"fmt"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"testing"
	"time"

	"github.com/7mind/wanbond/internal/bind"
)

// TestMultipathPerPath is the T12 per-path acceptance: the multipath Bind carries
// tunnel traffic over EACH configured path individually. Each subtest brings the
// bond up with exactly ONE path configured (the other "disabled" by omission) and
// verifies the WireGuard handshake completes and both ICMP and a TCP bulk transfer
// flow over that single path's source-bound socket + outer DATA framing.
func TestMultipathPerPath(t *testing.T) {
	bin := buildWanbond(t)
	for _, p := range DefaultPaths {
		p := p
		t.Run(p.name, func(t *testing.T) {
			top := Setup(t)
			edge, conc := setupMultipathTunnel(t, top, bin, []pathSpec{p})

			if !top.pingUntil(concInner, 15*time.Second) {
				t.Fatalf("path %q: tunnel never came up\n--- edge ---\n%s\n--- conc ---\n%s",
					p.name, edge.log(), conc.log())
			}
			mbps := top.iperf3Mbps(t, concInner, 3)
			if mbps <= 0 {
				t.Fatalf("path %q: iperf3 non-positive throughput %.2f Mbit/s", p.name, mbps)
			}
			t.Logf("multipath single-path [%s]: handshake + ping OK, iperf3 = %.1f Mbit/s", p.name, mbps)
		})
	}
}

// TestMultipathBothPathsAndFailover brings the bond up with BOTH paths configured,
// confirms the tunnel is up, then blackholes the secondary path and confirms the
// tunnel still carries traffic over the primary — demonstrating each path is an
// independent socket beneath the one virtual endpoint (the engine sees no churn).
// (Runtime scheduling/failover across paths is T15; T12's policy is "first healthy
// path", so the primary continues to carry traffic while the secondary is down.)
func TestMultipathBothPathsAndFailover(t *testing.T) {
	bin := buildWanbond(t)
	top := Setup(t)
	edge, conc := setupMultipathTunnel(t, top, bin, DefaultPaths)

	if !top.pingUntil(concInner, 15*time.Second) {
		t.Fatalf("bond never came up\n--- edge ---\n%s\n--- conc ---\n%s", edge.log(), conc.log())
	}

	// Blackhole the secondary path; the primary (first configured) still carries
	// traffic.
	top.Blackhole(DefaultPaths[1].name)
	if !top.pingUntil(concInner, 10*time.Second) {
		t.Fatalf("bond lost connectivity after blackholing secondary path %q\n--- edge ---\n%s",
			DefaultPaths[1].name, edge.log())
	}
	top.Restore(DefaultPaths[1].name)
	t.Logf("multipath both-paths: up over %d paths; survived blackhole of %q", len(DefaultPaths), DefaultPaths[1].name)
}

// TestMultipathInnerMTU asserts the TUN MTU the daemon set equals the computed
// inner MTU = path MTU − (outer IP/UDP + outer DATA frame + WG overhead), the
// fixture value pinned by the bind package's unit test.
func TestMultipathInnerMTU(t *testing.T) {
	bin := buildWanbond(t)
	top := Setup(t)
	setupMultipathTunnel(t, top, bin, DefaultPaths)

	// This fixture runs the daemon with FEC OFF (DefaultPaths carries no [fec] block),
	// so the TUN MTU is the FEC-off inner budget.
	want := bind.InnerMTU(bind.DefaultPathMTU, false)
	got := top.linkMTU(t, tunDev, false)
	if got != want {
		t.Fatalf("edge %s MTU = %d, want computed inner MTU %d", tunDev, got, want)
	}
	t.Logf("multipath inner MTU: %s MTU = %d (= %d path MTU − %d IP/UDP − %d DATA frame − %d WG)",
		tunDev, got, bind.DefaultPathMTU, bind.IPv4UDPOverhead, 40, bind.WGTransportOverhead)
}

// TestMultipathNoFragmentation sends a max-inner-MTU payload with the DF bit set
// through the tunnel and asserts, from a capture on the edge egress veth, that no
// outer datagram is IP-fragmented — the MTU accounting keeps a full inner packet
// inside the path MTU (no fragmentation, no PMTUD black hole).
func TestMultipathNoFragmentation(t *testing.T) {
	bin := buildWanbond(t)
	top := Setup(t)
	p := top.path("starlink")
	edge, _ := setupMultipathTunnel(t, top, bin, []pathSpec{p})

	if !top.pingUntil(concInner, 15*time.Second) {
		t.Fatalf("tunnel never came up\n%s", edge.log())
	}

	inner := bind.InnerMTU(bind.DefaultPathMTU, false)
	// ICMP echo payload that exactly fills the inner MTU: inner − 20 (IP) − 8 (ICMP).
	payload := inner - 28

	// Capture fragments on the edge egress veth while a DF-set, max-size ping runs.
	frags := top.captureFragments(t, p.edgeVeth, 6*time.Second, func() {
		out, err := exec.Command("ping", "-c", "5", "-s", strconv.Itoa(payload), "-M", "do", "-W", "2", concInner).CombinedOutput()
		if err != nil {
			t.Fatalf("DF max-MTU ping (payload %d) failed — inner packet does not fit the budget:\n%s", payload, out)
		}
	})
	if frags != 0 {
		t.Fatalf("observed %d IP-fragmented outer datagrams on %s during a max-inner-MTU transfer; MTU accounting is wrong", frags, p.edgeVeth)
	}
	t.Logf("multipath no-fragmentation: %d-byte inner packets (payload %d) produced no IP fragments on %s", inner, payload, p.edgeVeth)
}

// setupMultipathTunnel brings the multipath tunnel up over the given paths: the
// edge binds one source-addr'd socket per path and targets each path's
// concentrator address via dest_addr; the concentrator binds one socket per path
// on its own address. It addresses both TUNs and returns the running processes.
func setupMultipathTunnel(t *testing.T, top *Topology, bin string, paths []pathSpec) (edge, conc *proc) {
	t.Helper()
	return setupMultipathTunnelLevel(t, top, bin, paths, "error")
}

// setupMultipathTunnelLevel is setupMultipathTunnel with an explicit daemon log
// level. The P1 failover measurement (TestP1Failover) runs both daemons at "info"
// so the scheduler's per-direction "active path change" transitions are captured in
// each process's log for the root-cause evidence; every other caller uses "error".
func setupMultipathTunnelLevel(t *testing.T, top *Topology, bin string, paths []pathSpec, level string) (edge, conc *proc) {
	t.Helper()

	edgePriv, edgePub := genKey(t)
	concPriv, concPub := genKey(t)
	psk := randKey(t)

	var edgePaths, concPaths strings.Builder
	for _, p := range paths {
		fmt.Fprintf(&edgePaths, "[[paths]]\nname = %q\nsource_addr = %q\ndest_addr = \"%s:%d\"\n\n", p.name, p.edgeIP, p.concIP, listenPort)
		fmt.Fprintf(&concPaths, "[[paths]]\nname = %q\nsource_addr = %q\n\n", p.name, p.concIP)
	}
	// The wireguard peer endpoint (edge -> concentrator) seeds the virtual
	// endpoint; the primary path's concentrator address serves.
	primary := paths[0]

	dir := t.TempDir()
	edgeCfg := writeConfig(t, filepath.Join(dir, "edge.toml"), fmt.Sprintf(`role = "edge"
psk = "%s"

%s[wireguard]
private_key = "%s"

[[wireguard.peers]]
public_key = "%s"
endpoint = "%s:%d"
allowed_ips = ["%s/32"]

[log]
level = %q
`, psk, edgePaths.String(), edgePriv, concPub, primary.concIP, listenPort, concInner, level))

	concCfg := writeConfig(t, filepath.Join(dir, "conc.toml"), fmt.Sprintf(`role = "concentrator"
psk = "%s"

%s[wireguard]
private_key = "%s"
listen_port = %d

[[wireguard.peers]]
public_key = "%s"
allowed_ips = ["%s/32"]

[log]
level = %q
`, psk, concPaths.String(), concPriv, listenPort, edgePub, edgeInner, level))

	conc = top.startProc(t, "concentrator", "nsenter", "-t", strconv.Itoa(top.pid), "-n", bin, "--config", concCfg)
	edge = top.startProc(t, "edge", bin, "--config", edgeCfg)

	if !top.waitLink(tunDev, false, 5*time.Second) {
		t.Fatalf("edge %s never appeared\n%s", tunDev, edge.log())
	}
	if !top.waitLink(tunDev, true, 5*time.Second) {
		t.Fatalf("concentrator %s never appeared\n%s", tunDev, conc.log())
	}
	top.run("ip", "addr", "add", edgeInner+"/24", "dev", tunDev)
	top.run("ip", "link", "set", tunDev, "up")
	top.nsenter("ip", "addr", "add", concInner+"/24", "dev", tunDev)
	top.nsenter("ip", "link", "set", tunDev, "up")
	return edge, conc
}

// linkMTU returns the MTU of dev (in the peer netns when ns is true).
func (top *Topology) linkMTU(t *testing.T, dev string, ns bool) int {
	t.Helper()
	var out string
	if ns {
		out = top.runOut("nsenter", "-t", strconv.Itoa(top.pid), "-n", "ip", "-o", "link", "show", dev)
	} else {
		out = top.runOut("ip", "-o", "link", "show", dev)
	}
	// ... mtu 1401 ...
	fields := strings.Fields(out)
	for i, f := range fields {
		if f == "mtu" && i+1 < len(fields) {
			mtu, err := strconv.Atoi(fields[i+1])
			if err != nil {
				t.Fatalf("parse mtu %q: %v", fields[i+1], err)
			}
			return mtu
		}
	}
	t.Fatalf("no mtu field in %q", out)
	return 0
}

// captureFragments runs tcpdump on veth for the duration of during(), counting
// IP-fragmented datagrams (tcpdump annotates them "(frag ...)").
func (top *Topology) captureFragments(t *testing.T, veth string, d time.Duration, during func()) int {
	t.Helper()
	secs := int(d.Seconds())
	if secs < 1 {
		secs = 1
	}
	cap := exec.Command("timeout", strconv.Itoa(secs), "tcpdump", "-n", "-l", "-i", veth)
	out := &lockedBuffer{}
	cap.Stdout, cap.Stderr = out, out
	if err := cap.Start(); err != nil {
		t.Fatalf("start tcpdump on %s: %v", veth, err)
	}
	time.Sleep(700 * time.Millisecond) // let tcpdump attach before generating traffic
	during()
	time.Sleep(300 * time.Millisecond) // let trailing packets flush to the capture
	_ = cap.Wait()                     // timeout terminates it

	count := 0
	for _, line := range strings.Split(out.String(), "\n") {
		if strings.Contains(line, "frag ") {
			count++
		}
	}
	return count
}

//go:build e2e

package e2e

import (
	"time"

	"github.com/7mind/wanbond/internal/telemetry"
)

// Acceptance thresholds (Q1). These are the single source of truth for the
// per-phase verification criteria; every e2e assertion reads them from here so
// retuning after real-link measurements is a one-line change. Values are the
// approved Q1 defaults.
const (
	// P1RecoverySeconds bounds transparent-failover recovery: after the active
	// WAN is killed, the surviving TCP flow must have throughput restored within
	// this many seconds, with no connection reset.
	P1RecoverySeconds = 3

	// P2BondedMinFraction is the minimum bonded throughput as a fraction of the
	// sum of the two paths' individual throughputs, under saturating load.
	P2BondedMinFraction = 0.85
	// P2MeteredMaxByteFraction caps the metered (5G) path's share of total bytes
	// while the primary (Starlink) path is healthy — data-thrift.
	P2MeteredMaxByteFraction = 0.01

	// P3MinRecoveredFraction is the minimum fraction of lost DATA frames the RS
	// FEC must recover without retransmit, at each injected loss rate.
	P3MinRecoveredFraction = 0.95
	// P3MaxOverheadFactor bounds measured FEC overhead as a multiple of the
	// configured parity ratio.
	P3MaxOverheadFactor = 2.0

	// P4ResidualLossMax is the maximum post-recovery residual loss under steady
	// P4SteadyLossRate path loss with adaptive FEC engaged.
	P4ResidualLossMax = 0.005
	// P4SteadyLossRate is the steady per-path loss rate at which the P4 residual
	// and overhead-vs-baseline comparisons are made.
	P4SteadyLossRate = 0.05
)

// P3InjectedLossRates are the uniform loss rates at which fixed-ratio FEC
// recovery and overhead are asserted (P3).
var P3InjectedLossRates = []float64{0.05, 0.15}

// P4 adaptive-overhead acceptance is a comparison, not a scalar: for equal loss
// masking, adaptive total overhead bytes must be <= the P3 fixed-FEC baseline
// bytes. The comparison is performed in the P4 e2e test against a recorded
// baseline run rather than a constant here.

// Per-path liveness detection (T13/T39). Path liveness is entirely ours — the inner
// WireGuard keepalive is per-peer, not per-path — so a blackholed uplink under a
// live peer is detected only by these probes. These are NOT independent constants:
// they are ALIASES of the daemon's telemetry.Default* timing, so the e2e asserts
// against the exact cadence the daemon runs. This is the D16 reconciliation — there
// is one source of truth (internal/telemetry), not two tables that drift apart.
// PLivenessDownAfter is the silence (no authenticated probe echo) after which an up
// path is marked down; PLivenessProbeInterval is the probe/Tick cadence; detection
// latency is therefore bounded by DownAfter plus roughly one interval, and the e2e
// asserts a blackholed path is marked down within PLivenessDetectBudget.
//
// Relationship to P1RecoverySeconds (the 3s failover-recovery budget). Killing the
// ACTIVE WAN must restore the surviving flow within P1RecoverySeconds in BOTH
// directions. Recovery in EACH direction is (that side marks the path down) +
// (its scheduler reroutes, a sub-ms data-structure update). Crucially, failover is
// BIDIRECTIONAL and the two ends detect INDEPENDENTLY: the edge must mark the path
// down to reroute egress, AND the concentrator must mark it down to reroute its
// replies (D15/D16 — the earlier note budgeted only the edge term). Both detection
// clocks start at the kill and run CONCURRENTLY, so end-to-end bidirectional
// recovery is governed by the SLOWER of the two ends, not their sum:
//
//	recovery ≈ max(edgeDetect, concDetect) + reroute
//	         ≈ (DownAfter + one interval) + reroute        [the two ends are symmetric]
//	         = 1.2s + 0.2s + sub-ms ≈ 1.4s                 [worst-case detect, strict-'>' Tick]
//	         < PLivenessFailoverBudget = 1.6s              [budget adds one interval of headroom]
//
// So the NO-LOAD analytical recovery FLOOR is the detect term, DownAfter + one
// interval = 1.4s (the strict-'>' Tick needs one full interval past DownAfter to
// fire) plus a sub-ms reroute. PLivenessFailoverBudget = DownAfter + TWO intervals =
// 1.6s deliberately carries ONE interval BEYOND that 1.4s detect as headroom — it is
// a bound with slack, not the detect floor itself. The remaining ~1.4s up to the 3s
// deadline (3.0s − 1.6s) is the margin for CPU-scheduling jitter under a saturating
// flow — the D15 tail. Two T39 changes
// bought that margin back after the tail was found at ~3.1s: DownAfter was tightened
// 1500ms→1200ms and the interval 250ms→200ms (detect floor 1.75s→1.4s) WITHOUT reducing the
// six-lost-echo false-down tolerance (the ratio is unchanged); and the bind now
// advances liveness off the always-scheduled receive path too (D15), so a starved
// probe-loop timer no longer delays the concentrator-side detect. The correctness
// invariant when retuning is PLivenessFailoverBudget < P1RecoverySeconds, and the
// operational target is that MEASURED recovery under saturating load stays below
// P1RecoverySeconds every run — TestP1Failover is the guard.
//
// NOTE PLivenessDetectBudget is deliberately LARGER than PLivenessFailoverBudget: it
// is the SINGLE-PATH blackhole ASSERTION DEADLINE for TestLivenessBlackhole (detect
// worst-case + harness slack so that pump-loop e2e is not flaky), NOT the
// failover-composition term.
const (
	PLivenessProbeInterval = telemetry.DefaultProbeInterval
	PLivenessDownAfter     = telemetry.DefaultDownAfter
	PLivenessUpSuccesses   = telemetry.DefaultUpSuccesses
	// PLivenessFailoverBudget is the analytical per-direction failover-recovery bound:
	// the 1.4s worst-case detect (DownAfter + one interval, strict-'>' Tick) plus one
	// interval of headroom, = DownAfter + 2 intervals = 1.6s (the sub-ms reroute is
	// absorbed by that headroom). Both directions are symmetric and detect concurrently,
	// so it bounds end-to-end BIDIRECTIONAL recovery. It MUST stay below P1RecoverySeconds
	// (1.6s < 3s, a ~1.4s jitter margin); TestP1Failover asserts measured recovery against
	// P1RecoverySeconds and reports its margin against this budget.
	PLivenessFailoverBudget = PLivenessDownAfter + 2*PLivenessProbeInterval
	// PLivenessDetectBudget is the single-path blackhole assertion deadline (harness
	// slack added on top of the analytical detect), NOT the failover budget.
	PLivenessDetectBudget = PLivenessDownAfter + 1500*time.Millisecond
)

	ps := peer.paths[idx]
	remote, ok := ps.getRemote()
	if !ok {
		m.mu.Unlock()
		return errNoHealthyPath
	}
	c := ps.conn
	wires := make([]fecWire, 0, len(bufs))
	for _, b := range bufs {
		seq := peer.outerSeq.Add(1)
		if peer.fecSend != nil {
			// FEC on (T24): admit the inner datagram (coded as seq || inner) to the group
			// encoder. The returned data shard rides a normal DATA frame carrying its FEC
			// group + shard index; when this admission FILLS the group the encoder returns
			// the group's parity shards, emitted here as KindParity frames on the SAME
			// chosen path. Spreading parity onto a DIFFERENT path than its data (so one
			// path outage cannot lose both) is a documented future refinement, deliberately
			// NOT implemented here (see the T24 design notes).
			ds, parity, err := peer.fecSend.enc.Admit(fecShardPayload(seq, b))
			if err != nil {
				m.mu.Unlock()
				return err
			}
			wire, err := peer.sendCodec.Encode(nil, frame.Data{OuterSeq: seq, PathID: ps.id, FECGroup: uint32(ds.Group), FECIndex: uint8(ds.Index), Payload: b})
			if err != nil {
				m.mu.Unlock()
				return err
			}
			wires = append(wires, fecWire{b: wire})
			for _, par := range parity {
				pw, err := m.encodeParityLocked(peer, par, ps.id)
				if err != nil {
					m.mu.Unlock()
					return err
				}
				wires = append(wires, fecWire{b: pw, parity: true})
			}
			continue
		}
		wire, err := peer.sendCodec.Encode(nil, frame.Data{OuterSeq: seq, PathID: ps.id, Payload: b})
		if err != nil {
			m.mu.Unlock()
			return err
		}
		wires = append(wires, fecWire{b: wire})
	}
	fs := peer.fecSend
	m.mu.Unlock()

	for _, w := range wires {
		if _, err := c.WriteToUDPAddrPort(w.b, remote); err != nil {
			return err
		}
		// Per-path egress-wire accounting (T23): count the OUTER frame bytes just written
		// to this path (DATA and any FEC PARITY alike), lock-free and only for a datagram
		// that actually reached the socket. Send serialized the path choice under m.mu, so
		// ps is fixed here and this is the sole writer of ps.txBytes for this frame.
		ps.txBytes.Add(uint64(len(w.b)))
		if fs != nil {
			// FEC frame accounting (T24/T25), counted only once the frame reached the socket
			// so the /metrics overhead ratio reflects wire cost actually spent. Parity and
			// DATA are charged to disjoint counters; their ratio ParityFrames/DataFrames is
			// the fixed-ratio overhead the P3 e2e asserts against M/K. fs != nil only when FEC
			// is enabled, so a plain (FEC-off) datapath increments neither counter.
			if w.parity {
				fs.parityFrames.Add(1)
				fs.parityBytes.Add(uint64(len(w.b)))
			} else {
				fs.dataFrames.Add(1)
				// DATA-frame wire bytes: the overhead-BYTES denominator (T29). The P4
				// acceptance compares parity BYTES / data BYTES, so both are counted on the
				// same only-once-it-reached-the-socket basis as the frame counters.
				fs.dataBytes.Add(uint64(len(w.b)))
			}
		}
	}
	return nil
}

// fecWire is one framed outgoing datagram tagged with whether it is an FEC parity
// frame, so the write loop can charge parity-overhead accounting (T24) without a
// second pass.
type fecWire struct {
	b      []byte
	parity bool
}

// encodeParityLocked encodes one parity shard as a KindParity frame on the given
// path, using the owning peer's send Codec. Caller holds m.mu (the send Codec is
// shared and stateful per peer).
func (m *Multipath) encodeParityLocked(peer *peerState, par fec.ParityShard, pathID uint8) ([]byte, error) {
	return peer.sendCodec.Encode(nil, frame.Parity{
		FECGroup:    uint32(par.Group),
		ParityIndex: uint16(par.Index),
		DataCount:   uint8(par.DataCount),
		PathID:      pathID,
		Payload:     par.Payload,
	})
}

// fecTickLoop drives the FEC encoder's grouping deadline (T24): a partially-filled
// group whose size threshold has not been reached is closed on time so its parity is
// emitted rather than stranded until the next data frame. It ticks at the configured
// deadline period and exits on recvClosed. It is tracked by readersWG so Close waits
// for it. Like tickLivenessFromReceive it only ever TryLocks m.mu, so it can never
// deadlock Close's readersWG.Wait (which runs while Close holds m.mu).
func (m *Multipath) fecTickLoop(period time.Duration, closed <-chan struct{}) {
	defer m.readersWG.Done()
	ticker := time.NewTicker(period)
	defer ticker.Stop()
	for {
		select {
		case <-closed:
			return
		case <-ticker.C:
			m.fecFlushDeadline()
		}
	}
}

// fecFlushDeadline closes any FEC group whose grouping deadline has elapsed and emits
// its parity on a scheduler-chosen path. It TryLocks m.mu: when the lock is contended
// (a concurrent Send/Close/AddPath) it simply skips this tick — the next tick, or the
// next size-triggered close, still emits the group's parity, and skipping preserves
// Close's invariant that no readersWG goroutine blocks on m.mu. Framing runs under the
// lock (the shared stateful send Codec); the socket writes run without it, mirroring
// Send.
func (m *Multipath) fecFlushDeadline() {
	if !m.mu.TryLock() {
		return
	}
	if m.fecSend == nil || len(m.paths) == 0 {
		m.mu.Unlock()
		return
	}
	// Adaptive drive (T29): fold a fresh loss sample into the controller and retarget the
	// encoder's per-group parity BEFORE flushing, so a group closed by this tick already
	// carries the current target. It is a no-op in fixed mode and self-throttles to the
	// probe cadence. Runs under the same m.mu the flush holds — the single serialized FEC
	// locus — so the controller (a state machine) is never touched concurrently.
	m.driveAdaptiveControllerLocked()
	parity, err := m.fecSend.enc.Tick()
	if err != nil || len(parity) == 0 {
		m.mu.Unlock()
		return
	}
	// Route the parity like data through the scheduler (a first-integration choice; see
	// Send). A shed/no-path verdict drops this group's parity — a degraded path is
	// exactly when the datapath is under pressure, and a stranded partial group's parity
	// is best-effort — so the group simply goes unprotected rather than blocking. FEC
	// parity is bulk redundancy, so it is paced as ClassData (defect D22): only WireGuard
	// control frames earn the pacing exemption.
	idx := m.scheduler.Pick(sched.ClassData)
	if idx < 0 || idx >= len(m.paths) {
		m.mu.Unlock()
		return
	}
	ps := m.paths[idx]
	remote, ok := ps.getRemote()
	if !ok {
		m.mu.Unlock()
		return
	}
	c := ps.conn
	fs := m.fecSend
	wires := make([][]byte, 0, len(parity))
	for _, par := range parity {
		// fecFlushDeadline drives the PRIMARY peer's FEC group (m.fecSend/m.scheduler/
		// m.paths reach the primary by promotion), so its parity is framed with the
		// primary's send Codec.
		pw, err := m.encodeParityLocked(m.peerState, par, ps.id)
		if err != nil {
			m.mu.Unlock()
			return
		}
		wires = append(wires, pw)
	}
	m.mu.Unlock()

	for _, wire := range wires {
		if _, err := c.WriteToUDPAddrPort(wire, remote); err != nil {
			return
		}
		ps.txBytes.Add(uint64(len(wire)))
		fs.parityFrames.Add(1)
		fs.parityBytes.Add(uint64(len(wire)))
	}
}

// driveAdaptiveControllerLocked folds one measured loss sample into the adaptive FEC
// controller and retargets the encoder's per-group parity (T29). Caller holds m.mu, so
// the controller — a state machine that is NOT safe for concurrent use — is driven from
// this single serialized locus (the FEC tick loop), exactly as the encoder is. It is a
// no-op in fixed-ratio mode (no controller) and self-throttles to adaptiveControlInterval
// so the controller's EWMA sees ~one sample per probe interval regardless of the tick rate.
//
// WHICH LOSS drives the controller (design decision 1): the MAX raw probe-measured loss
// (Estimate().Loss) across the currently-eligible (StateUp) paths. Parity must mask the
// loss the DATA actually experiences; under active-backup only the primary carries data
// and the max collapses to it, and under the weighted scheduler data is striped across the
// eligible set, so sizing to the worst active path is the defensible, policy-agnostic
// choice. It is deliberately the RAW per-path loss, NOT the post-recovery ConnLoss: feeding
// the masked residual back would form a control loop that under-provisions precisely because
// it is succeeding. A down/probeless path is excluded — it carries no data to protect.
func (m *Multipath) driveAdaptiveControllerLocked() {
	fs := m.fecSend
	if fs.ctrl == nil {
		return // fixed-ratio mode
	}
	now := time.Now()
	if fs.haveControlTick && now.Sub(fs.lastControlTick) < adaptiveControlInterval {
		return
	}
	fs.lastControlTick = now
	fs.haveControlTick = true

	loss, have := m.maxEligiblePathLossLocked()
	if !have {
		return // no eligible probed path this interval: hold the current target
	}

